                } elseif ($connectId === 'public') {
                    $response = Async\await($this->publicPostBulletPublic ($params));
                } elseif ($connectId === 'privateFutures') {
                    $response = Async\await($this->futuresPrivatePostBulletPrivate ($params));
                } else {
